SELECT CUSTOMER.CODE, CUSTOMER.CPYNAME, CUSTOMER.CUSCLASS, CUSTOMER.PROFILE, CUSTOMER.CURR, CUSTOMER.TERR, Exchange.RATE, Exchange.DESC, CUSTOMER.UF_ALTPROF1, CUSTOMER.UF_ALTPROF2, CUSTOMER.UF_ALTPROF3, CUSTOMER.UF_ALTPROF4, CUSTOMER.UF_ALTPROF5, CUSTOMER.UF_ALTPROF6, CUSTOMER.UF_ALTPROF7, CUSTOMER.UF_ALTPROF8, CUSTOMER.UF_ALTPROF9, CUSTOMER.UF_ALTPROF10, CUSTOMER.UF_ALTPROF11 FROM CUSTOMER JOIN Exchange ON CUSTOMER.CURR = Exchange.CODE;
